import * as React from "react";

/** A generated Material Symbols icon: an <svg> accepting all SVG props + ref. */
export type Md3Icon = React.ForwardRefExoticComponent<
  Omit<React.SVGProps<SVGSVGElement>, "ref"> & React.RefAttributes<SVGSVGElement>
>;

export declare function createIcon(displayName: string, d: string): Md3Icon;
